import React, { useState, memo, useCallback } from "react";
import { colorBarra, estadoLabel, formatearFechaHora } from "../../utils/formatters";
import Button from "../Shared/Button";

function CardObra({ obra, onActualizar }) {
  const [abierta, setAbierta] = useState(false);
  const estado = estadoLabel(obra.estado);

  const toggle = useCallback(() => setAbierta((v) => !v), []);

  return (
    <div className="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
      {/* Header siempre visible */}
      <button
        onClick={toggle}
        className="w-full text-left px-4 py-3 flex items-center justify-between gap-3 hover:bg-gray-50 transition-colors"
        aria-expanded={abierta}
      >
        <div className="flex-1 min-w-0">
          <p className="font-medium text-gray-800 text-sm truncate">{obra.nombre}</p>
          <p className="text-xs text-gray-400 mt-0.5 truncate">{obra.programa}</p>
        </div>
        <div className="flex items-center gap-2 shrink-0">
          <span className={`badge ${estado.clase} text-xs`}>
            {estado.icono} {estado.label}
          </span>
          <svg
            className={`w-4 h-4 text-gray-400 transition-transform duration-200 ${abierta ? "rotate-180" : ""}`}
            fill="none" viewBox="0 0 24 24" stroke="currentColor"
          >
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        </div>
      </button>

      {/* Detalles expandibles */}
      {abierta && (
        <div className="px-4 pb-4 border-t border-gray-100 animate-fade-in">
          {/* Barra de progreso */}
          <div className="mt-3">
            <div className="flex justify-between text-xs text-gray-500 mb-1">
              <span>Avance</span>
              <span className="font-semibold">{obra.porcentaje}%</span>
            </div>
            <div className="w-full bg-gray-100 rounded-full h-2">
              <div
                className={`h-2 rounded-full transition-all duration-500 ${colorBarra(obra.porcentaje)}`}
                style={{ width: `${obra.porcentaje}%` }}
              />
            </div>
          </div>

          <div className="mt-3 grid grid-cols-2 gap-2 text-xs text-gray-500">
            <div>
              <span className="font-medium text-gray-600">Última actualización</span>
              <p>{formatearFechaHora(obra.ultimaActualizacion)}</p>
            </div>
            <div>
              <span className="font-medium text-gray-600">Usuario</span>
              <p className="truncate">{obra.usuario || "—"}</p>
            </div>
          </div>

          <div className="mt-3">
            <Button
              size="sm"
              onClick={() => onActualizar?.(obra)}
              className="w-full"
              aria-label={`Actualizar obra ${obra.nombre}`}
            >
              Actualizar avance
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

export default memo(CardObra);
